fn _imax(i1: u32, i2: u32) -> u32 {
    if i1 > i2 { i1 } else { i2 }
}

fn _bostree_balance(node: &Rc<RefCell<BOSNode>>) -> i32 {
    let borrow = node.borrow();
    let left_depth = borrow.left_child_node.as_ref().map_or(0, |l| l.borrow().depth + 1);
    let right_depth = borrow.right_child_node.as_ref().map_or(0, |r| r.borrow().depth + 1);
    (right_depth as i32) - (left_depth as i32)
}

fn _bostree_rotate_right(tree: &mut BOSTree, p: Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    let l = Rc::clone(p.borrow().left_child_node.as_ref().unwrap());

    let p_parent = p.borrow().parent_node.clone().and_then(|w| w.upgrade());
    if let Some(ref parent) = p_parent {
        let is_left = parent.borrow().left_child_node.as_ref().map_or(false, |child| Rc::ptr_eq(child, &p));
        if is_left {
            parent.borrow_mut().left_child_node = Some(Rc::clone(&l));
        } else {
            parent.borrow_mut().right_child_node = Some(Rc::clone(&l));
        }
    } else {
        tree.root_node = Some(Rc::clone(&l));
    }

    l.borrow_mut().parent_node = p.borrow().parent_node.clone();

    let l_right = l.borrow().right_child_node.clone();
    let l_right_count = l.borrow().right_child_count;
    p.borrow_mut().left_child_node = l_right.clone();
    p.borrow_mut().left_child_count = l_right_count;

    if let Some(ref lr) = l_right {
        lr.borrow_mut().parent_node = Some(Rc::downgrade(&p));
    }

    let p_left_depth = p.borrow().left_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
    let p_right_depth = p.borrow().right_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
    p.borrow_mut().depth = _imax(p_left_depth, p_right_depth);

    p.borrow_mut().parent_node = Some(Rc::downgrade(&l));

    l.borrow_mut().right_child_node = Some(Rc::clone(&p));
    let p_left_count = p.borrow().left_child_count;
    let p_right_count = p.borrow().right_child_count;
    l.borrow_mut().right_child_count = p_left_count + p_right_count + 1;

    let l_left_depth = l.borrow().left_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
    let l_right_depth = l.borrow().right_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
    l.borrow_mut().depth = _imax(l_left_depth, l_right_depth);

    l
}

fn _bostree_rotate_left(tree: &mut BOSTree, p: Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    let r = Rc::clone(p.borrow().right_child_node.as_ref().unwrap());

    let p_parent = p.borrow().parent_node.clone().and_then(|w| w.upgrade());
    if let Some(ref parent) = p_parent {
        let is_left = parent.borrow().left_child_node.as_ref().map_or(false, |child| Rc::ptr_eq(child, &p));
        if is_left {
            parent.borrow_mut().left_child_node = Some(Rc::clone(&r));
        } else {
            parent.borrow_mut().right_child_node = Some(Rc::clone(&r));
        }
    } else {
        tree.root_node = Some(Rc::clone(&r));
    }

    r.borrow_mut().parent_node = p.borrow().parent_node.clone();

    let r_left = r.borrow().left_child_node.clone();
    let r_left_count = r.borrow().left_child_count;
    p.borrow_mut().right_child_node = r_left.clone();
    p.borrow_mut().right_child_count = r_left_count;

    if let Some(ref rl) = r_left {
        rl.borrow_mut().parent_node = Some(Rc::downgrade(&p));
    }

    let p_left_depth = p.borrow().left_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
    let p_right_depth = p.borrow().right_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
    p.borrow_mut().depth = _imax(p_left_depth, p_right_depth);

    p.borrow_mut().parent_node = Some(Rc::downgrade(&r));

    r.borrow_mut().left_child_node = Some(Rc::clone(&p));
    let p_left_count = p.borrow().left_child_count;
    let p_right_count = p.borrow().right_child_count;
    r.borrow_mut().left_child_count = p_left_count + p_right_count + 1;

    let r_left_depth = r.borrow().left_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
    let r_right_depth = r.borrow().right_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
    r.borrow_mut().depth = _imax(r_left_depth, r_right_depth);

    r
}

impl BOSTree {
    pub fn bostree_new(
        cmp_function: BOSTreeCmpFunction,
        free_function: Option<BOSTreeFreeFunction>,
    ) -> Self {
        BOSTree {
            root_node: None,
            cmp_function,
            free_function,
        }
    }

    pub fn bostree_node_count(&self) -> u32 {
        if let Some(ref root) = self.root_node {
            let borrow = root.borrow();
            borrow.left_child_count + borrow.right_child_count + 1
        } else {
            0
        }
    }

    pub fn bostree_insert(&mut self, key: String, data: Option<String>) -> Rc<RefCell<BOSNode>> {
        let mut parent_node: Option<Rc<RefCell<BOSNode>>> = None;
        let mut current_opt = self.root_node.clone();

        while let Some(node) = current_opt {
            parent_node = Some(Rc::clone(&node));
            let cmp = (self.cmp_function)(&key, &node.borrow().key);
            if cmp < 0 {
                node.borrow_mut().left_child_count += 1;
                current_opt = node.borrow().left_child_node.clone();
            } else {
                node.borrow_mut().right_child_count += 1;
                current_opt = node.borrow().right_child_node.clone();
            }
        }

        let new_node = Rc::new(RefCell::new(BOSNode {
            key: key.clone(),
            data,
            weak_ref_count: 1,
            weak_ref_node_valid: 1,
            parent_node: parent_node.as_ref().map(|p| Rc::downgrade(p)),
            left_child_node: None,
            right_child_node: None,
            left_child_count: 0,
            right_child_count: 0,
            depth: 0,
        }));

        if let Some(ref parent) = parent_node {
            let cmp = (self.cmp_function)(&key, &parent.borrow().key);
            if cmp < 0 {
                parent.borrow_mut().left_child_node = Some(Rc::clone(&new_node));
            } else {
                parent.borrow_mut().right_child_node = Some(Rc::clone(&new_node));
            }
        } else {
            self.root_node = Some(Rc::clone(&new_node));
            return new_node;
        }

        let mut curr_parent = parent_node.unwrap();
        let depth_changed = {
            let pb = curr_parent.borrow();
            (pb.left_child_node.is_some() as u8 ^ pb.right_child_node.is_some() as u8) != 0
        };

        if depth_changed {
            curr_parent.borrow_mut().depth += 1;

            while let Some(next_parent) = curr_parent.borrow().parent_node.clone().and_then(|w| w.upgrade()) {
                curr_parent = next_parent;

                let new_left_depth = curr_parent.borrow().left_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
                let new_right_depth = curr_parent.borrow().right_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
                let max_depth = _imax(new_left_depth, new_right_depth);

                if curr_parent.borrow().depth != max_depth {
                    curr_parent.borrow_mut().depth = max_depth;
                } else {
                    break;
                }

                if new_left_depth == new_right_depth + 2 {
                    let left = curr_parent.borrow().left_child_node.clone().unwrap();
                    if _bostree_balance(&left) > 0 {
                        _bostree_rotate_left(self, left);
                    }
                    curr_parent = _bostree_rotate_right(self, curr_parent);
                } else if new_left_depth + 2 == new_right_depth {
                    let right = curr_parent.borrow().right_child_node.clone().unwrap();
                    if _bostree_balance(&right) < 0 {
                        _bostree_rotate_right(self, right);
                    }
                    curr_parent = _bostree_rotate_left(self, curr_parent);
                }
            }
        }

        new_node
    }

    pub fn bostree_remove(&mut self, node: &Rc<RefCell<BOSNode>>) {
        let mut bubble_up: Option<Rc<RefCell<BOSNode>>> = None;

        let has_left = node.borrow().left_child_node.is_some();
        let has_right = node.borrow().right_child_node.is_some();

        if has_left && has_right {
            let left_depth = node.borrow().left_child_node.as_ref().unwrap().borrow().depth;
            let right_depth = node.borrow().right_child_node.as_ref().unwrap().borrow().depth;

            let mut candidate: Rc<RefCell<BOSNode>>;
            let mut lost_child: Option<Rc<RefCell<BOSNode>>>;

            if left_depth >= right_depth {
                node.borrow_mut().left_child_count -= 1;
                candidate = Rc::clone(node.borrow().left_child_node.as_ref().unwrap());
                while candidate.borrow().right_child_node.is_some() {
                    candidate.borrow_mut().right_child_count -= 1;
                    let next = Rc::clone(candidate.borrow().right_child_node.as_ref().unwrap());
                    candidate = next;
                }
                lost_child = candidate.borrow().left_child_node.clone();
            } else {
                node.borrow_mut().right_child_count -= 1;
                candidate = Rc::clone(node.borrow().right_child_node.as_ref().unwrap());
                while candidate.borrow().left_child_node.is_some() {
                    candidate.borrow_mut().left_child_count -= 1;
                    let next = Rc::clone(candidate.borrow().left_child_node.as_ref().unwrap());
                    candidate = next;
                }
                lost_child = candidate.borrow().right_child_node.clone();
            }

            let bubble_start = candidate.borrow().parent_node.clone().unwrap().upgrade().unwrap();

            let is_bubble_start_left = bubble_start.borrow().left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &candidate));
            if is_bubble_start_left {
                bubble_start.borrow_mut().left_child_node = lost_child.clone();
            } else {
                bubble_start.borrow_mut().right_child_node = lost_child.clone();
            }

            if let Some(ref lc) = lost_child {
                lc.borrow_mut().parent_node = Some(Rc::downgrade(&bubble_start));
            }

            if let Some(parent_rc) = node.borrow().parent_node.clone().and_then(|w| w.upgrade()) {
                let is_node_left = parent_rc.borrow().left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, node));
                if is_node_left {
                    parent_rc.borrow_mut().left_child_node = Some(Rc::clone(&candidate));
                } else {
                    parent_rc.borrow_mut().right_child_node = Some(Rc::clone(&candidate));
                }
            } else {
                self.root_node = Some(Rc::clone(&candidate));
            }
            candidate.borrow_mut().parent_node = node.borrow().parent_node.clone();

            candidate.borrow_mut().left_child_node = node.borrow().left_child_node.clone();
            candidate.borrow_mut().left_child_count = node.borrow().left_child_count;
            candidate.borrow_mut().right_child_node = node.borrow().right_child_node.clone();
            candidate.borrow_mut().right_child_count = node.borrow().right_child_count;

            if let Some(ref c_left) = candidate.borrow().left_child_node {
                c_left.borrow_mut().parent_node = Some(Rc::downgrade(&candidate));
            }
            if let Some(ref c_right) = candidate.borrow().right_child_node {
                c_right.borrow_mut().parent_node = Some(Rc::downgrade(&candidate));
            }

            if !Rc::ptr_eq(&bubble_start, node) {
                let mut bs = bubble_start;
                while !Rc::ptr_eq(&bs, &candidate) {
                    let bs_left_depth = bs.borrow().left_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
                    let bs_right_depth = bs.borrow().right_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
                    bs.borrow_mut().depth = _imax(bs_left_depth, bs_right_depth);

                    let balance = _bostree_balance(&bs);
                    if balance > 1 {
                        let right = bs.borrow().right_child_node.clone().unwrap();
                        if _bostree_balance(&right) < 0 {
                            _bostree_rotate_right(self, right);
                        }
                        bs = _bostree_rotate_left(self, bs);
                    } else if balance < -1 {
                        let left = bs.borrow().left_child_node.clone().unwrap();
                        if _bostree_balance(&left) > 0 {
                            _bostree_rotate_left(self, left);
                        }
                        bs = _bostree_rotate_right(self, bs);
                    }
                    let p = bs.borrow().parent_node.clone().unwrap().upgrade().unwrap();
                    bs = p;
                }
            }

            let c_left_depth = candidate.borrow().left_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
            let c_right_depth = candidate.borrow().right_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
            candidate.borrow_mut().depth = _imax(c_left_depth, c_right_depth);

            bubble_up = candidate.borrow().parent_node.clone().and_then(|w| w.upgrade());

            if let Some(ref bu) = bubble_up {
                let is_c_left = bu.borrow().left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &candidate));
                if is_c_left {
                    bu.borrow_mut().left_child_count -= 1;
                } else {
                    bu.borrow_mut().right_child_count -= 1;
                }
            }

        } else {
            let parent_opt = node.borrow().parent_node.clone().and_then(|w| w.upgrade());
            if parent_opt.is_none() {
                if let Some(ref left) = node.borrow().left_child_node {
                    self.root_node = Some(Rc::clone(left));
                    left.borrow_mut().parent_node = None;
                } else if let Some(ref right) = node.borrow().right_child_node {
                    self.root_node = Some(Rc::clone(right));
                    right.borrow_mut().parent_node = None;
                } else {
                    self.root_node = None;
                }
                bubble_up = None;
            } else {
                let parent = parent_opt.unwrap();
                let mut candidate = node.borrow().left_child_node.clone();
                let mut candidate_count = node.borrow().left_child_count;
                if node.borrow().right_child_node.is_some() {
                    candidate = node.borrow().right_child_node.clone();
                    candidate_count = node.borrow().right_child_count;
                }

                let is_node_left = parent.borrow().left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, node));
                if is_node_left {
                    parent.borrow_mut().left_child_node = candidate.clone();
                    parent.borrow_mut().left_child_count = candidate_count;
                } else {
                    parent.borrow_mut().right_child_node = candidate.clone();
                    parent.borrow_mut().right_child_count = candidate_count;
                }

                if let Some(ref c) = candidate {
                    c.borrow_mut().parent_node = Some(Rc::downgrade(&parent));
                }

                bubble_up = Some(parent);
            }
        }

        let mut bubbling_finished = false;
        let mut bu_opt = bubble_up;
        while let Some(mut bu) = bu_opt {
            if !bubbling_finished {
                let left_depth = bu.borrow().left_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
                let right_depth = bu.borrow().right_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
                let new_depth = _imax(left_depth, right_depth);
                let depth_changed = new_depth != bu.borrow().depth;
                bu.borrow_mut().depth = new_depth;

                let balance = _bostree_balance(&bu);
                if balance < -1 {
                    let left = bu.borrow().left_child_node.clone().unwrap();
                    if _bostree_balance(&left) > 0 {
                        _bostree_rotate_left(self, left);
                    }
                    bu = _bostree_rotate_right(self, bu);
                } else if balance > 1 {
                    let right = bu.borrow().right_child_node.clone().unwrap();
                    if _bostree_balance(&right) < 0 {
                        _bostree_rotate_right(self, right);
                    }
                    bu = _bostree_rotate_left(self, bu);
                } else {
                    if !depth_changed {
                        bubbling_finished = true;
                    }
                }
            }

            let p_opt = bu.borrow().parent_node.clone().and_then(|w| w.upgrade());
            if let Some(ref p) = p_opt {
                let is_bu_left = p.borrow().left_child_node.as_ref().map_or(false, |c| Rc::ptr_eq(c, &bu));
                if is_bu_left {
                    p.borrow_mut().left_child_count -= 1;
                } else {
                    p.borrow_mut().right_child_count -= 1;
                }
            }
            bu_opt = p_opt;
        }

        node.borrow_mut().weak_ref_node_valid = 0;
        self.bostree_node_weak_unref(node);
    }

    pub fn bostree_node_weak_unref(
        &mut self,
        node: &Rc<RefCell<BOSNode>>,
    ) -> Option<Rc<RefCell<BOSNode>>> {
        let mut borrow = node.borrow_mut();
        borrow.weak_ref_count -= 1;
        if borrow.weak_ref_count == 0 {
            if let Some(free_func) = self.free_function {
                drop(borrow);
                free_func(node);
            }
            None
        } else if borrow.weak_ref_node_valid != 0 {
            drop(borrow);
            Some(Rc::clone(node))
        } else {
            None
        }
    }

    pub fn bostree_lookup(&self, key: &str) -> Option<Rc<RefCell<BOSNode>>> {
        let mut current = self.root_node.clone();
        while let Some(node) = current {
            let cmp = (self.cmp_function)(key, &node.borrow().key);
            if cmp == 0 {
                return Some(node);
            } else if cmp < 0 {
                let left = node.borrow().left_child_node.clone();
                current = left;
            } else {
                let right = node.borrow().right_child_node.clone();
                current = right;
            }
        }
        None
    }

    pub fn bostree_select(&self, mut index: u32) -> Option<Rc<RefCell<BOSNode>>> {
        let mut current = self.root_node.clone();
        while let Some(node) = current.clone() {
            let left_count = node.borrow().left_child_count;
            if left_count <= index {
                index -= left_count;
                if index == 0 {
                    return Some(node);
                }
                index -= 1;
                current = node.borrow().right_child_node.clone();
            } else {
                current = node.borrow().left_child_node.clone();
            }
        }
        None
    }

    #[cfg(debug_assertions)]
    pub fn bostree_print(&self) {
        if self.root_node.is_none() {
            return;
        }
        println!("digraph {{\n  ordering = out;");
        fn helper(node: &Rc<RefCell<BOSNode>>) {
            let b = node.borrow();
            println!("  {} [label=\"\\N ({},{},{})\"];", b.key, b.left_child_count, b.right_child_count, b.depth);
            if let Some(ref p_weak) = b.parent_node {
                if let Some(p) = p_weak.upgrade() {
                    println!("  {} -> {} [color=green];", b.key, p.borrow().key);
                }
            }
            if let Some(ref l) = b.left_child_node {
                println!("  {} -> {}", b.key, l.borrow().key);
                helper(l);
            }
            if let Some(ref r) = b.right_child_node {
                println!("  {} -> {}", b.key, r.borrow().key);
                helper(r);
            }
        }
        if let Some(ref r) = self.root_node {
            helper(r);
        }
        println!("}}");
    }
}

pub fn bostree_node_weak_ref(node: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    assert!(node.borrow().weak_ref_count < 127);
    assert!(node.borrow().weak_ref_count > 0);
    node.borrow_mut().weak_ref_count += 1;
    Rc::clone(node)
}

pub fn bostree_next_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    if let Some(ref right) = node.borrow().right_child_node {
        let mut current = Rc::clone(right);
        loop {
            let next_left = current.borrow().left_child_node.clone();
            if let Some(left) = next_left {
                current = left;
            } else {
                return Some(current);
            }
        }
    } else {
        let mut current = Rc::clone(node);
        loop {
            let parent_weak = current.borrow().parent_node.clone();
            if let Some(parent_rc) = parent_weak.and_then(|w| w.upgrade()) {
                let is_right_child = {
                    let parent_borrow = parent_rc.borrow();
                    if let Some(ref parent_right) = parent_borrow.right_child_node {
                        Rc::ptr_eq(parent_right, &current)
                    } else {
                        false
                    }
                };
                if is_right_child {
                    current = parent_rc;
                } else {
                    return Some(parent_rc);
                }
            } else {
                return None;
            }
        }
    }
}

pub fn bostree_previous_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    if let Some(ref left) = node.borrow().left_child_node {
        let mut current = Rc::clone(left);
        loop {
            let next_right = current.borrow().right_child_node.clone();
            if let Some(right) = next_right {
                current = right;
            } else {
                return Some(current);
            }
        }
    } else {
        let mut current = Rc::clone(node);
        loop {
            let parent_weak = current.borrow().parent_node.clone();
            if let Some(parent_rc) = parent_weak.and_then(|w| w.upgrade()) {
                let is_left_child = {
                    let parent_borrow = parent_rc.borrow();
                    if let Some(ref parent_left) = parent_borrow.left_child_node {
                        Rc::ptr_eq(parent_left, &current)
                    } else {
                        false
                    }
                };
                if is_left_child {
                    current = parent_rc;
                } else {
                    return Some(parent_rc);
                }
            } else {
                return None;
            }
        }
    }
}

pub fn bostree_rank(node: &Rc<RefCell<BOSNode>>) -> u32 {
    let mut counter = node.borrow().left_child_count;
    let mut current = Rc::clone(node);
    loop {
        let parent_weak = current.borrow().parent_node.clone();
        if let Some(parent_rc) = parent_weak.and_then(|w| w.upgrade()) {
            let is_right_child = {
                let parent_borrow = parent_rc.borrow();
                if let Some(ref parent_right) = parent_borrow.right_child_node {
                    Rc::ptr_eq(parent_right, &current)
                } else {
                    false
                }
            };
            if is_right_child {
                counter += 1 + parent_rc.borrow().left_child_count;
            }
            current = parent_rc;
        } else {
            break;
        }
    }
    counter
}
